classDiagram(name = "LogisticsNetwork") {
    val trackable = interfaceOf(name = "Trackable") {
        operation(name = "track") { returns(typeName = "String") }
    }

    val warehouse = classOf(name = "Warehouse") {
        attribute(name = "name", type = "String")
    }

    val storageLocation = classOf(name = "StorageLocation") {
        attribute(name = "code", type = "String")
    }

    val shipmentStatus = enumOf(name = "ShipmentStatus") {
        literal(name = "ACCEPTED")
        literal(name = "IN_WAREHOUSE")
        literal(name = "IN_TRANSIT")
        literal(name = "DELIVERED")
    }

    val shipment = classOf(name = "Shipment") {
        attribute(name = "trackingNumber", type = "String")
        attribute(name = "status", type = "ShipmentStatus")
        implements(iface = trackable)
    }

    val pkg = classOf(name = "Package") {
        attribute(name = "packageId", type = "String")
    }

    val route = classOf(name = "Route") {
        attribute(name = "name", type = "String")
    }

    val segment = classOf(name = "Segment") {
        attribute(name = "sequenceNumber", type = "Int")
    }

    val vehicle = classOf(name = "Vehicle") {
        isAbstract = true
        attribute(name = "licensePlate", type = "String")
    }

    val truck = classOf(name = "Truck") {
        extends(general = vehicle)
        attribute(name = "trailerCoupling", type = "Boolean")
    }

    val van = classOf(name = "Van") {
        extends(general = vehicle)
        attribute(name = "cargoVolume", type = "Double")
    }

    val driver = classOf(name = "Driver") {
        attribute(name = "name", type = "String")
    }

    val tour = classOf(name = "Tour") {
        attribute(name = "tourId", type = "String")
    }

    // Warehouse consists of storage locations
    association(source = warehouse, target = storageLocation) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "storageLocations" }
    }

    // Shipment consists of at least one package
    association(source = shipment, target = pkg) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "packages" }
    }

    // Package can be temporarily assigned to a storage location
    association(source = pkg, target = storageLocation) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "0..1"); role = "currentLocation" }
    }

    // Route made up of segments
    association(source = route, target = segment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "segments" }
    }

    // Segment runs from a source warehouse to a destination warehouse
    association(source = segment, target = warehouse) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "sourceWarehouse" }
    }

    association(source = segment, target = warehouse) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "destinationWarehouse" }
    }

    // Tour connects exactly one vehicle, one driver, one route, delivers any number of shipments
    association(source = tour, target = vehicle) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "vehicle" }
    }

    association(source = tour, target = driver) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "driver" }
    }

    association(source = tour, target = route) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "route" }
    }

    association(source = tour, target = shipment) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "shipments" }
    }
}

