classDiagram(name = "HospitalInformationSystem") {
    val personForm = classOf(name = "PersonForm") {
        isAbstract = true
        attribute(name = "firstName", type = "String")
        attribute(name = "lastName", type = "String")
        attribute(name = "dateOfBirth", type = "String")
    }

    val patient = classOf(name = "Patient") {
        extends(general = personForm)
    }

    val doctor = classOf(name = "Doctor") {
        extends(general = personForm)
    }

    val nurse = classOf(name = "Nurse") {
        extends(general = personForm)
    }

    val ward = classOf(name = "Ward") {
        attribute(name = "name", type = "String")
    }

    val bed = classOf(name = "Bed") {
        attribute(name = "bedNumber", type = "String")
    }

    val admissionType = enumOf(name = "AdmissionType") {
        literal(name = "EMERGENCY")
        literal(name = "PLANNED")
        literal(name = "TRANSFER")
    }

    val inpatientStay = classOf(name = "InpatientStay") {
        attribute(name = "admissionType", type = "AdmissionType")
    }

    val diagnosis = classOf(name = "Diagnosis") {
        attribute(name = "description", type = "String")
    }

    val prescription = classOf(name = "Prescription") {
        attribute(name = "dosage", type = "String")
    }

    val medication = classOf(name = "Medication") {
        attribute(name = "name", type = "String")
    }

    val insuranceCompany = classOf(name = "InsuranceCompany") {
        attribute(name = "name", type = "String")
    }

    val invoice = classOf(name = "Invoice") {
        attribute(name = "amount", type = "String")
    }

    val billingContract = classOf(name = "BillingContract") {
        attribute(name = "terms", type = "String")
    }

    // Ward consists of beds (composition)
    association(source = ward, target = bed) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "beds" }
    }

    // Ward staffed by at least one nurse
    association(source = ward, target = nurse) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "nurses" }
    }

    // Each stay belongs to exactly one patient
    association(source = inpatientStay, target = patient) {
        source { multiplicity(spec = "0..*"); role = "stays" }
        target { multiplicity(spec = "1") }
    }

    // Each stay occupies at most one bed
    association(source = inpatientStay, target = bed) {
        source { multiplicity(spec = "0..*"); role = "stays" }
        target { multiplicity(spec = "0..1") }
    }

    // Each stay has exactly one attending physician
    association(source = inpatientStay, target = doctor) {
        source { multiplicity(spec = "0..*"); role = "stays" }
        target { multiplicity(spec = "1"); role = "attendingPhysician" }
    }

    // Diagnoses belong inseparably to the stay (composition)
    association(source = inpatientStay, target = diagnosis) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "diagnoses" }
    }

    // Each diagnosis is the responsibility of exactly one doctor
    association(source = diagnosis, target = doctor) {
        source { multiplicity(spec = "0..*"); role = "diagnoses" }
        target { multiplicity(spec = "1"); role = "responsibleDoctor" }
    }

    // Prescriptions can be issued for a diagnosis
    association(source = diagnosis, target = prescription) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "prescriptions" }
    }

    // Each prescription specifies exactly one medication
    association(source = prescription, target = medication) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1") }
    }

    // Each patient is insured by exactly one insurance company
    association(source = patient, target = insuranceCompany) {
        source { multiplicity(spec = "0..*"); role = "patients" }
        target { multiplicity(spec = "1") }
    }

    // Each stay generates exactly one invoice
    association(source = inpatientStay, target = invoice) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "invoice" }
    }

    // Invoice follows a uniform billing contract
    association(source = invoice, target = billingContract) {
        source { multiplicity(spec = "0..*"); role = "invoices" }
        target { multiplicity(spec = "1") }
    }

    // Invoice is submitted to the insurance company
    association(source = invoice, target = insuranceCompany) {
        source { multiplicity(spec = "0..*"); role = "invoices" }
        target { multiplicity(spec = "1") }
    }
}

