sequenceDiagram(name = "ApiGatewayRateLimiting") {
    val client = lifeline(name = "Client") { isActor = true }
    val gateway = lifeline(name = "API Gateway")
    val rateLimiter = lifeline(name = "Rate Limiter")
    val backend = lifeline(name = "Backend Service")

    loop(guard = "[up to 3 attempts]") {
        message(from = client, to = gateway, label = "request data()")
        message(from = gateway, to = rateLimiter, label = "check quota()")
        alt {
            branch(guard = "[quota available]") {
                reply(from = rateLimiter, to = gateway, label = "quota ok")
                message(from = gateway, to = backend, label = "forward request()")
                reply(from = backend, to = gateway, label = "data")
                reply(from = gateway, to = client, label = "data")
            }
            branch(guard = "[quota exhausted]") {
                reply(from = rateLimiter, to = gateway, label = "quota exceeded")
                reply(from = gateway, to = client, label = "429 too many requests")
                message(from = client, to = client, label = "wait backoff period()")
            }
        }
    }
}

sequenceDiagram(name = "PasswordReset") {
    val user = lifeline(name = "User") { isActor = true }
    val portal = lifeline(name = "Web Portal")
    val auth = lifeline(name = "Authentication Service")
    val db = lifeline(name = "User Database")
    val mail = lifeline(name = "Email Sender")

    message(from = user, to = portal, label = "requestPasswordReset(email)")
    message(from = portal, to = auth, label = "requestPasswordReset(email)")
    message(from = auth, to = db, label = "lookupUser(email)")
    reply(from = db, to = auth, label = "user record or none")

    alt {
        branch(guard = "[user exists]") {
            message(from = auth, to = auth, label = "generateResetToken()")
            message(from = auth, to = db, label = "storeResetToken(token)")
            reply(from = db, to = auth, label = "ack")
            asyncMessage(from = auth, to = mail, label = "sendResetEmail(email, token)")
        }
        branch(guard = "[user unknown]") {
            message(from = auth, to = auth, label = "noOp()")
        }
    }

    reply(from = auth, to = portal, label = "neutral success message")
    reply(from = portal, to = user, label = "neutral notification")
}

sequenceDiagram(name = "OrderRequestAuth") {
    val client = lifeline(name = "Client") { isActor = true }
    val gateway = lifeline(name = "APIGateway")
    val cache = lifeline(name = "TokenCache")
    val auth = lifeline(name = "AuthenticationService")
    val orderService = lifeline(name = "OrderService")

    message(from = client, to = gateway, label = "callOrderEndpoint(jwt)")
    message(from = gateway, to = cache, label = "checkToken(jwt)")
    reply(from = cache, to = gateway, label = "cacheResult")

    opt(guard = "[no cache entry]") {
        message(from = gateway, to = auth, label = "verifyToken(jwt)")
        reply(from = auth, to = gateway, label = "verificationResult")
        message(from = gateway, to = cache, label = "storeResult(verificationResult)")
    }

    alt {
        branch(guard = "[token valid]") {
            message(from = gateway, to = orderService, label = "forwardRequest()")
            reply(from = orderService, to = gateway, label = "orderList")
            reply(from = gateway, to = client, label = "orderList")
        }
        branch(guard = "[token invalid]") {
            reply(from = gateway, to = client, label = "accessDenied")
        }
    }
}

sequenceDiagram(name = "OrderSagaOrchestration") {
    val customer = lifeline(name = "Customer") { isActor = true }
    val orderService = lifeline(name = "OrderService")
    val orchestrator = lifeline(name = "SagaOrchestrator")
    val eventLog = lifeline(name = "EventLog")
    val warehouseService = lifeline(name = "WarehouseService")
    val paymentService = lifeline(name = "PaymentService")
    val shipmentService = lifeline(name = "ShipmentService")

    message(from = customer, to = orderService, label = "placeOrder()")
    create(from = orderService, to = orchestrator)

    message(from = orchestrator, to = warehouseService, label = "reserveItems()")
    reply(from = warehouseService, to = orchestrator, label = "reservationResult")
    asyncMessage(from = orchestrator, to = eventLog, label = "logReservationStep()")

    alt {
        branch(guard = "[goods available]") {
            message(from = orchestrator, to = paymentService, label = "executePayment()")
            reply(from = paymentService, to = orchestrator, label = "paymentResult")
            asyncMessage(from = orchestrator, to = eventLog, label = "logPaymentStep()")

            alt {
                branch(guard = "[payment succeeded]") {
                    message(from = orchestrator, to = shipmentService, label = "commissionShipment()")
                    reply(from = shipmentService, to = orchestrator, label = "shipmentResult")
                    asyncMessage(from = orchestrator, to = eventLog, label = "logShipmentStep()")
                }
                branch(guard = "[payment failed]") {
                    message(from = orchestrator, to = warehouseService, label = "cancelReservation()")
                    reply(from = warehouseService, to = orchestrator, label = "cancellationConfirmed")
                    asyncMessage(from = orchestrator, to = eventLog, label = "logCompensationStep()")
                }
            }
        }
        branch(guard = "[goods not available]") {
            asyncMessage(from = orchestrator, to = eventLog, label = "logAbortStep()")
        }
    }

    delete(from = orderService, to = orchestrator)
    message(from = orderService, to = customer, label = "orderStatus")
}

sequenceDiagram(name = "OAuth Login Flow") {
    val user = lifeline(name = "User") { isActor = true }
    val client = lifeline(name = "Client Application")
    val authServer = lifeline(name = "Authorization Server")
    val sessionStore = lifeline(name = "Session Store")
    val auditLog = lifeline(name = "Audit Log")
    val resourceServer = lifeline(name = "Resource Server")

    message(from = user, to = client, label = "initiate login()")
    message(from = client, to = authServer, label = "redirect via browser")
    message(from = authServer, to = sessionStore, label = "create session(process)")
    reply(from = sessionStore, to = authServer, label = "session created")
    message(from = authServer, to = user, label = "deliver login form")
    message(from = user, to = authServer, label = "enter credentials()")

    alt {
        branch(guard = "[credentials valid]") {
            message(from = authServer, to = user, label = "issue authorization code")
            message(from = user, to = client, label = "authorization code (callback)")
            message(from = client, to = authServer, label = "exchange code for access token()")
            par {
                branch {
                    reply(from = authServer, to = client, label = "access token")
                }
                branch {
                    message(from = authServer, to = auditLog, label = "note issuance()")
                }
            }
            opt(guard = "[scope includes profile]") {
                message(from = client, to = resourceServer, label = "get user data()")
                message(from = resourceServer, to = authServer, label = "re-verify token()")
                reply(from = authServer, to = resourceServer, label = "token valid")
                reply(from = resourceServer, to = client, label = "user data")
            }
        }
        branch(guard = "[credentials wrong]") {
            delete(from = authServer, to = sessionStore)
            message(from = authServer, to = user, label = "show error message")
        }
    }
}

sequenceDiagram(name = "CollisionAvoidance") {
    val camera = lifeline(name = "Camera")
    val radar = lifeline(name = "Radar")
    val fusion = lifeline(name = "FusionUnit")
    val assistant = lifeline(name = "EmergencyBrakingAssistant")
    val driver = lifeline(name = "Driver") { isActor = true }
    val control = lifeline(name = "ControlUnit")
    val diagLog = lifeline(name = "DiagnosticLog")

    par {
        branch { asyncMessage(from = camera, to = fusion, label = "deliverMeasurementData()") }
        branch { asyncMessage(from = radar, to = fusion, label = "deliverMeasurementData()") }
    }

    message(from = fusion, to = fusion, label = "computeConsolidatedEnvironmentModel()")
    message(from = fusion, to = assistant, label = "reportCollisionRisk(timeToCollision)")

    alt {
        branch(guard = "[timeToCollision < criticalThreshold]") {
            message(from = assistant, to = driver, label = "warnAcoustically()")
            message(from = assistant, to = assistant, label = "initiateAutonomousBrakingManeuver()")
            loop(guard = "[vehicle not stationary]") {
                message(from = assistant, to = control, label = "adjustBrakePressure()")
            }
            message(from = assistant, to = assistant, label = "endManeuver()")
            message(from = assistant, to = diagLog, label = "recordEvent()")
        }
        branch(guard = "[timeToCollision >= criticalThreshold]") {
            par {
                branch { opt(guard = "[distance warning warranted]") { message(from = assistant, to = driver, label = "showDistanceWarning()") } }
                branch { message(from = assistant, to = diagLog, label = "logObservedRisk()") }
            }
        }
    }
}

