    relationship(source = orchestrator, target = evaluationService) { technology = "HTTPS"; description = "Triggers result evaluation" }
    relationship(source = evaluationService, target = dataLake) { technology = "HTTPS"; description = "Checks results against expected values" }

    relationship(source = testEngineer, target = webInterface) { technology = "HTTPS"; description = "Defines test campaigns" }
    relationship(source = fleetManager, target = webInterface) { technology = "HTTPS"; description = "Monitors vehicle status" }
    relationship(source = webInterface, target = orchestrator) { technology = "HTTPS"; description = "Manages test campaigns" }

    relationship(source = orchestrator, target = simulationScheduler) { technology = "HTTPS"; description = "Dispatches scenarios to the simulation environment" }
    relationship(source = simulationScheduler, target = physicsEngine) { technology = "HTTPS"; description = "Distributes simulation jobs" }
    relationship(source = physicsEngine, target = simulationScheduler) { technology = "HTTPS"; description = "Reports simulation results back" }
    relationship(source = simulationScheduler, target = orchestrator) { technology = "HTTPS"; description = "Reports simulation results back" }
    relationship(source = physicsEngine, target = hdMapService) { technology = "HTTPS"; description = "Retrieves high-resolution map material" }

