import dev.kuml.sysml2.dsl.sysml2Model
import dev.kuml.kerml.KermlMultiplicity

sysml2Model(name = "Drivetrain") {
    val cell = partDef(name = "Battery Cell")
    val batteryModule = partDef(name = "Battery Module") {
        part(name = "cells", typeId = cell.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
    }
    val batteryPack = partDef(name = "High-Voltage Battery Pack") {
        part(name = "modules", typeId = batteryModule.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
    }
    val inverter = partDef(name = "Inverter")
    val electricMotor = partDef(name = "Electric Motor")
    val gearbox = partDef(name = "Gearbox")
    val bms = partDef(name = "Battery Management System")
    val thermalManagementSystem = partDef(name = "Thermal Management System")

    val drivetrainSystem = partDef(name = "Drivetrain System") {
        part(name = "batteryPack", typeId = batteryPack.id)
        part(name = "inverter", typeId = inverter.id)
        part(name = "motors", typeId = electricMotor.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
        part(name = "gearbox", typeId = gearbox.id)
    }

    val vehicle = partDef(name = "Vehicle") {
        part(name = "drivetrain", typeId = drivetrainSystem.id)
        part(name = "bms", typeId = bms.id)
        part(name = "thermalManagement", typeId = thermalManagementSystem.id)
    }

    bdd(name = "Drivetrain BDD") {
        include(vehicle)
        include(drivetrainSystem)
        include(batteryPack)
        include(batteryModule)
        include(cell)
        include(inverter)
        include(electricMotor)
        include(gearbox)
        include(bms)
        include(thermalManagementSystem)
    }
}
